// KACE Maschinen in Lookup-Map umwandeln
const kaceData = $input.first().json;
const machines = kaceData.Machines || [];

// Erstelle Map: hostname (lowercase) -> user info
const userLookup = new Map();

for (const machine of machines) {
  const name = (machine.Name || '').toLowerCase().trim();
  const user = machine.User || machine.Last_User || '';
  const userFullname = machine.User_Fullname || '';
  const ip = machine.Ip || '';

  if (name) {
    userLookup.set(name, {
      user: user,
      userFullname: userFullname,
      kaceIp: ip,
      kaceName: machine.Name
    });

    // Auch FQDN-Varianten speichern
    // z.B. 'server01' und 'server01.domain.com' sollten matchen
    const shortName = name.split('.')[0];
    if (shortName && !userLookup.has(shortName)) {
      userLookup.set(shortName, {
        user: user,
        userFullname: userFullname,
        kaceIp: ip,
        kaceName: machine.Name
      });
    }
  }
}

console.log(`KACE Lookup erstellt: ${userLookup.size} Einträge`);

return [{
  json: {
    userLookup: Object.fromEntries(userLookup),
    totalMachines: machines.length
  }
}];

const response = $input.first().json;
const total = response.total;
const maxResults = 2500;
const pages = Math.ceil(total / maxResults);

console.log(`Total Open Jira Tickets: ${total}, Pages needed: ${pages}`);

const pageRequests = [];
for (let i = 0; i < pages; i++) {
  pageRequests.push({
    startAt: i * maxResults,
    pageNumber: i + 1,
    totalPages: pages,
    totalTickets: total
  });
}

return pageRequests.map(p => ({ json: p }));

// Hole alle Inputs
const allItems = $input.all();

// Finde KACE Lookup (kommt aus dem zweiten Input)
let userLookup = {};
let allIssues = [];

for (const item of allItems) {
  if (item.json.userLookup) {
    userLookup = item.json.userLookup;
  }
  if (item.json.issues) {
    allIssues.push(...item.json.issues);
  }
}

console.log(`Verarbeite ${allIssues.length} Jira Tickets mit ${Object.keys(userLookup).length} KACE Einträgen`);

// Gruppiere nach Vulnerability (Summary)
const vulnerabilityMap = new Map();
let matchedHosts = 0;
let unmatchedHosts = 0;

for (const issue of allIssues) {
  const summary = issue.fields.summary || 'Unknown Vulnerability';
  const key = issue.key;
  const status = issue.fields.status?.name || 'Unknown';
  const priority = issue.fields.priority?.name || 'Unknown';

  // Custom Fields auslesen
  const hostname = issue.fields.customfield_34832 || 'Unknown Host';
  const ip = issue.fields.customfield_35049 || '';
  const severity = issue.fields.customfield_34800?.value || 'Unknown';
  const os = issue.fields.customfield_34904?.value || '';
  const cveLink = issue.fields.customfield_34803 || '';

  // KACE User Lookup
  const hostnameLower = hostname.toLowerCase().trim();
  const shortHostname = hostnameLower.split('.')[0];

  let kaceUser = '';
  let kaceUserFullname = '';

  // Versuche verschiedene Matching-Strategien
  if (userLookup[hostnameLower]) {
    kaceUser = userLookup[hostnameLower].user;
    kaceUserFullname = userLookup[hostnameLower].userFullname;
    matchedHosts++;
  } else if (userLookup[shortHostname]) {
    kaceUser = userLookup[shortHostname].user;
    kaceUserFullname = userLookup[shortHostname].userFullname;
    matchedHosts++;
  } else {
    unmatchedHosts++;
  }

  if (!vulnerabilityMap.has(summary)) {
    vulnerabilityMap.set(summary, {
      vulnerability: summary,
      severity: severity,
      cveLink: cveLink,
      affectedHosts: [],
      ticketKeys: [],
      count: 0
    });
  }

  const vuln = vulnerabilityMap.get(summary);

  // Prüfe ob Host bereits in der Liste
  const existingHost = vuln.affectedHosts.find(h => h.hostname === hostname);
  if (!existingHost) {
    vuln.affectedHosts.push({
      hostname: hostname,
      ip: ip,
      os: os,
      status: status,
      ticketKey: key,
      user: kaceUser,
      userFullname: kaceUserFullname
    });
    vuln.ticketKeys.push(key);
    vuln.count++;
  }
}

// Sortiere nach Anzahl betroffener Hosts
const consolidated = Array.from(vulnerabilityMap.values())
  .sort((a, b) => b.count - a.count);

// Statistiken
const stats = {
  totalTickets: allIssues.length,
  uniqueVulnerabilities: consolidated.length,
  criticalCount: consolidated.filter(v => v.severity === 'Critical').length,
  highCount: consolidated.filter(v => v.severity === 'High').length,
  mediumCount: consolidated.filter(v => v.severity === 'Medium').length,
  lowCount: consolidated.filter(v => v.severity === 'Low').length,
  maxAffectedHosts: consolidated.length > 0 ? consolidated[0].count : 0,
  kaceMatchedHosts: matchedHosts,
  kaceUnmatchedHosts: unmatchedHosts,
  kaceMatchRate: allIssues.length > 0 ? Math.round((matchedHosts / allIssues.length) * 100) : 0
};

console.log(`KACE Match Rate: ${stats.kaceMatchRate}% (${matchedHosts} matched, ${unmatchedHosts} unmatched)`);

return [{
  json: {
    stats: stats,
    consolidated: consolidated
  }
}];

