// KACE: JWT Token + kboxid Session Cookie extrahieren
const response = $input.first().json;
const body = response.body || response;

if (body.errorCode || body.errorDescription) {
  throw new Error('KACE Login fehlgeschlagen: ' + (body.errorDescription || body.errorCode));
}

const cookies = response.headers?.['set-cookie'] || [];
const cookieList = Array.isArray(cookies) ? cookies : [cookies];

let token = null;
let kboxid = null;

for (const cookie of cookieList) {
  const jwtMatch = cookie.match(/x-kace-auth-jwt=([^;]+)/i);
  if (jwtMatch) token = jwtMatch[1].trim();

  const kboxMatch = cookie.match(/kboxid=([^;]+)/i);
  if (kboxMatch) kboxid = kboxMatch[1].trim();
}

if (!token) throw new Error('x-kace-auth-jwt nicht gefunden!');
if (!kboxid) throw new Error('kboxid nicht gefunden!');

console.log('✅ JWT Token extrahiert:', token.substring(0, 20) + '...');
console.log('✅ kboxid extrahiert:', kboxid.substring(0, 10) + '...');

return [{ json: { token, kboxid, bearerHeader: 'Bearer ' + token } }];
